import ast
import socket

HOST = 'crypto.chal.csaw.io'
PORT = 8000

# Challenge curve params from server.py
P = 14753
A = 1
ORDER = 7919
G = (1, 1)

def inv_mod(n, p):
    return pow(n, -1, p)

def add(P1, P2):
    if P1 is None:
        return P2
    if P2 is None:
        return P1

    x1, y1 = P1
    x2, y2 = P2

    # P + (-P) = O
    if x1 == x2 and (y1 + y2) % P == 0:
        return None

    if x1 == x2:
        m = ((3 * x1 * x1 + A) * inv_mod((2 * y1) % P, P)) % P
    else:
        m = ((y1 - y2) * inv_mod((x1 - x2) % P, P)) % P

    x3 = (m * m - x1 - x2) % P
    y3 = (-(y1 + m * (x3 - x1))) % P
    return (x3, y3)

def build_dlog_table():
    table = {None: 0}
    R = None
    for k in range(1, ORDER):
        R = add(R, G)
        # keep first hit only
        if R not in table:
            table[R] = k
    return table

def recv_until(sock, token: bytes):
    data = b''
    while token not in data:
        chunk = sock.recv(4096)
        if not chunk:
            break
        data += chunk
    return data

def main():
    table = build_dlog_table()

    s = socket.create_connection((HOST, PORT))

    blob = recv_until(s, b'Public key: ')
    rest = recv_until(s, b'\n')
    text = (blob + rest).decode(errors='ignore')

    pub_line = text.split('Public key: ')[1].split('\n')[0].strip()
    pub = ast.literal_eval(pub_line)

    secret = table[pub]

    # Usually prompt already arrived in previous reads; harmless if extra data remains.
    s.sendall(f"{secret}\n".encode())

    s.settimeout(2)
    out = b''
    try:
        while True:
            d = s.recv(4096)
            if not d:
                break
            out += d
    except Exception:
        pass

    print(out.decode(errors='ignore'))

if __name__ == '__main__':
    main()
